+
+        // Second pass: all hits.
+        let root_rects = inc.get_or_compute(root, a, |a| split_equal(a, 3));
+        for (i, &c) in children.iter().enumerate() {
+            inc.get_or_compute(c, root_rects[i], |a| split_equal(a, 1));
+        }
